import { useEffect, useState } from "react";
import styled from "styled-components";
import { supabase } from "../services/supabaseClient";

const Carrinho = () => {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchCart();
  }, []);

  async function fetchCart() {
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) return;

    const { data, error } = await supabase
      .from("carrinho")
      .select(`
        id,
        quantidade,
        produtos (
          id,
          nome,
          preco,
          imagem_url
        )
      `)
      .eq("user_id", user.id);

    if (!error) {
      setItems(data);
    }

    setLoading(false);
  }

  async function removeItem(id) {
    await supabase
      .from("carrinho")
      .delete()
      .eq("id", id);

    fetchCart();
  }

  async function updateQuantity(id, quantidade) {

    if (quantidade < 1) return;

    await supabase
      .from("carrinho")
      .update({ quantidade })
      .eq("id", id);

    fetchCart();
  }

  async function finalizarCompra() {

    const { data: { user } } = await supabase.auth.getUser();

    await supabase
      .from("carrinho")
      .delete()
      .eq("user_id", user.id);

    alert("Compra realizada com sucesso!");

    fetchCart();
  }

  const total = items.reduce((acc, item) => {
    return acc + item.produtos.preco * item.quantidade;
  }, 0);

  if (loading) return <Container>Carregando...</Container>;

  return (
    <Container>

      <h1>Seu Carrinho</h1>

      {items.length === 0 && <p>Seu carrinho está vazio.</p>}

      {items.map((item) => {

        const subtotal = item.produtos.preco * item.quantidade;

        return (
          <Card key={item.id}>

            <img src={item.produtos.imagem_url} alt="" />

            <Info>

              <h3>{item.produtos.nome}</h3>

              <p>Preço: R$ {item.produtos.preco}</p>

              <Quantidade>

                <button
                  onClick={() =>
                    updateQuantity(item.id, item.quantidade - 1)
                  }
                >
                  -
                </button>

                <span>{item.quantidade}</span>

                <button
                  onClick={() =>
                    updateQuantity(item.id, item.quantidade + 1)
                  }
                >
                  +
                </button>

              </Quantidade>

              <Subtotal>
                Subtotal: R$ {subtotal}
              </Subtotal>

            </Info>

            <RemoveButton
              onClick={() => removeItem(item.id)}
            >
              Remover
            </RemoveButton>

          </Card>
        );
      })}

      {items.length > 0 && (

        <Resumo>

          <h2>Total: R$ {total}</h2>

          <button onClick={finalizarCompra}>
            Finalizar compra
          </button>

        </Resumo>

      )}

    </Container>
  );
};

export default Carrinho;
